+        		}
+        		if((*it).ptr>newNode){
+            		nodes.insert(it, newData);
+            		inserted = true;
+            		ret = true;
+            		break;
+        		}        
+    		}
+    		if(!inserted){
+        		nodes.insert(nodes.end(), newData);
